package fan.summer.Registrar;

import com.toolbox.api.ToolPlugin;
import com.toolbox.plugin.PluginLoader;
import com.toolbox.plugin.PluginRegistry;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Node;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.TextArea;
import javafx.scene.control.TextField;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.Region;
import javafx.scene.layout.VBox;

/**
 * Built-in tool registrar.
 * Built-in tools implement the same ToolPlugin interface as external plugins, transparent to the main program.
 * Directly injected into PluginRegistry, bypassing PluginLoader JAR process.
 */
public class BuiltinToolRegistrar {

    public static void register(PluginLoader loader, PluginRegistry registry) {
        // Built-in tools are directly added到 registry（绕过 loader，无需 JAR）
        registry.getPlugins().addAll(
            jsonFormatter(),
            base64Tool(),
            hashTool(),
            colorConverter(),
            markdownEditor()
        );
    }

    // ════════════════════════════════════════════════════
    // Tool implementations
    // ════════════════════════════════════════════════════

    // ── JSON Formatter ───────────────────────────────────────

    private static ToolPlugin jsonFormatter() {
        return new SimpleToolPlugin(
            "builtin.json-formatter", "JSON Formatter",
            "Format, compress, and validate JSON data",
            "dev", "1.0.0", "{ }", "ic-blue"
        ) {
            @Override public Node createView() {
                TextArea input  = styledTextArea("Paste JSON......");
                TextArea output = styledTextArea("");
                output.setEditable(false);

                Button formatBtn  = actionButton("Format", "#5b8cf7");
                Button compactBtn = actionButton("Compact",   "rgba(255,255,255,0.12)");
                Button clearBtn   = actionButton("Clear",   "rgba(255,255,255,0.08)");

                formatBtn.setOnAction(e -> {
                    try {
                        // 简单演示：用换行和缩进模拟Format
                        String raw = input.getText().trim();
                        output.setText(prettyPrint(raw));
                        output.setStyle(output.getStyle());
                    } catch (Exception ex) {
                        output.setText("❌ Invalid JSON：" + ex.getMessage());
                    }
                });
                compactBtn.setOnAction(e ->
                    output.setText(input.getText().replaceAll("\\s+", ""))
                );
                clearBtn.setOnAction(e -> { input.clear(); output.clear(); });

                HBox btnRow = new HBox(8, formatBtn, compactBtn, clearBtn);
                btnRow.setPadding(new Insets(0, 0, 12, 0));

                VBox left  = new VBox(6, sectionLabel("Input"), input);
                VBox right = new VBox(6, sectionLabel("Output"), output);
                VBox.setVgrow(input,  Priority.ALWAYS);
                VBox.setVgrow(output, Priority.ALWAYS);
                HBox.setHgrow(left,   Priority.ALWAYS);
                HBox.setHgrow(right,  Priority.ALWAYS);

                HBox editors = new HBox(12, left, right);
                HBox.setHgrow(editors, Priority.ALWAYS);
                VBox.setVgrow(editors, Priority.ALWAYS);

                VBox root = new VBox(12, btnRow, editors);
                root.setPadding(new Insets(20));
                root.setStyle("-fx-background-color: transparent;");
                VBox.setVgrow(root, Priority.ALWAYS);
                return root;
            }

            private String prettyPrint(String json) {
                StringBuilder sb = new StringBuilder();
                int indent = 0;
                boolean inString = false;
                for (char c : json.toCharArray()) {
                    if (c == '"' && (sb.isEmpty() || sb.charAt(sb.length()-1) != '\\'))
                        inString = !inString;
                    if (!inString) {
                        if (c == '{' || c == '[') {
                            sb.append(c).append('\n');
                            indent += 2;
                            sb.append(" ".repeat(indent));
                            continue;
                        } else if (c == '}' || c == ']') {
                            sb.append('\n');
                            indent = Math.max(0, indent - 2);
                            sb.append(" ".repeat(indent)).append(c);
                            continue;
                        } else if (c == ',') {
                            sb.append(c).append('\n').append(" ".repeat(indent));
                            continue;
                        } else if (c == ':') {
                            sb.append(": ");
                            continue;
                        } else if (c == ' ' || c == '\n' || c == '\r' || c == '\t') {
                            continue;
                        }
                    }
                    sb.append(c);
                }
                return sb.toString();
            }
        };
    }

    // ── Base64 Encode/Decode ─────────────────────────────────────

    private static ToolPlugin base64Tool() {
        return new SimpleToolPlugin(
            "builtin.base64", "Base64",
            "Base64 Encode/Decode，支持文本与文件",
            "dev", "1.0.0", "64", "ic-teal"
        ) {
            @Override public Node createView() {
                TextArea input  = styledTextArea("Input文本...");
                TextArea output = styledTextArea("");
                output.setEditable(false);

                Button encodeBtn = actionButton("Encode →", "#5b8cf7");
                Button decodeBtn = actionButton("← Decode", "rgba(255,255,255,0.12)");
                Button swapBtn   = actionButton("↕ Swap", "rgba(255,255,255,0.08)");

                encodeBtn.setOnAction(e -> {
                    try {
                        byte[] encoded = java.util.Base64.getEncoder()
                            .encode(input.getText().getBytes(java.nio.charset.StandardCharsets.UTF_8));
                        output.setText(new String(encoded));
                    } catch (Exception ex) { output.setText("Error：" + ex.getMessage()); }
                });
                decodeBtn.setOnAction(e -> {
                    try {
                        byte[] decoded = java.util.Base64.getDecoder()
                            .decode(input.getText().trim());
                        output.setText(new String(decoded, java.nio.charset.StandardCharsets.UTF_8));
                    } catch (Exception ex) { output.setText("❌ 无效 Base64"); }
                });
                swapBtn.setOnAction(e -> {
                    String tmp = input.getText();
                    input.setText(output.getText());
                    output.setText(tmp);
                });

                HBox btnRow = new HBox(8, encodeBtn, decodeBtn, swapBtn);
                btnRow.setPadding(new Insets(0, 0, 12, 0));

                VBox left  = new VBox(6, sectionLabel("Input"), input);
                VBox right = new VBox(6, sectionLabel("Output"), output);
                VBox.setVgrow(input, Priority.ALWAYS);
                VBox.setVgrow(output, Priority.ALWAYS);
                HBox.setHgrow(left, Priority.ALWAYS);
                HBox.setHgrow(right, Priority.ALWAYS);

                HBox editors = new HBox(12, left, right);
                VBox.setVgrow(editors, Priority.ALWAYS);
                VBox root = new VBox(12, btnRow, editors);
                root.setPadding(new Insets(20));
                root.setStyle("-fx-background-color: transparent;");
                return root;
            }
        };
    }

    // ── Hash 计算 ─────────────────────────────────────────

    private static ToolPlugin hashTool() {
        return new SimpleToolPlugin(
            "builtin.hash", "Hash Calculator",
            "MD5 / SHA-1 / SHA-256 / SHA-512",
            "dev", "1.0.0", "#", "ic-amber"
        ) {
            @Override public Node createView() {
                TextArea input = styledTextArea("Input文本...");

                String[][] algos = {{"MD5","MD5"},{"SHA-1","SHA-1"},{"SHA-256","SHA-256"},{"SHA-512","SHA-512"}};
                VBox results = new VBox(8);

                Button calcBtn = actionButton("Calculate Hash", "#5b8cf7");
                calcBtn.setOnAction(e -> {
                    results.getChildren().clear();
                    for (String[] a : algos) {
                        try {
                            java.security.MessageDigest md =
                                java.security.MessageDigest.getInstance(a[1]);
                            byte[] hash = md.digest(
                                input.getText().getBytes(java.nio.charset.StandardCharsets.UTF_8));
                            StringBuilder hex = new StringBuilder();
                            for (byte b : hash) hex.append(String.format("%02x", b));
                            results.getChildren().add(hashRow(a[0], hex.toString()));
                        } catch (Exception ex) {
                            results.getChildren().add(hashRow(a[0], "Error"));
                        }
                    }
                });

                VBox root = new VBox(12,
                    sectionLabel("Input文本"), input,
                    calcBtn, sectionLabel("Result"), results
                );
                VBox.setVgrow(input, Priority.ALWAYS);
                root.setPadding(new Insets(20));
                root.setStyle("-fx-background-color: transparent;");
                return root;
            }

            private HBox hashRow(String algo, String value) {
                Label algoLabel = new Label(algo);
                algoLabel.setStyle(
                    "-fx-text-fill: rgba(255,255,255,0.45); -fx-font-size: 11px;" +
                    "-fx-min-width: 60px; -fx-font-family: 'SF Mono','Consolas',monospace;"
                );
                Label valueLabel = new Label(value);
                valueLabel.setStyle(
                    "-fx-text-fill: rgba(255,255,255,0.85); -fx-font-size: 11px;" +
                    "-fx-font-family: 'SF Mono','Consolas',monospace;"
                );
                valueLabel.setMaxWidth(Double.MAX_VALUE);
                HBox.setHgrow(valueLabel, Priority.ALWAYS);

                Button copy = new Button("Copy");
                copy.setStyle(
                    "-fx-background-color: rgba(255,255,255,0.08); -fx-border-width: 0;" +
                    "-fx-text-fill: rgba(255,255,255,0.5); -fx-font-size: 10px;" +
                    "-fx-background-radius: 4; -fx-cursor: hand; -fx-padding: 2 8 2 8;"
                );
                copy.setOnAction(e -> {
                    javafx.scene.input.Clipboard.getSystemClipboard().setContent(
                        new javafx.scene.input.ClipboardContent() {{ putString(value); }}
                    );
                    copy.setText("✓");
                    javafx.animation.PauseTransition pt =
                        new javafx.animation.PauseTransition(javafx.util.Duration.seconds(1.5));
                    pt.setOnFinished(ev -> copy.setText("Copy"));
                    pt.play();
                });

                HBox row = new HBox(10, algoLabel, valueLabel, copy);
                row.setAlignment(Pos.CENTER_LEFT);
                row.setStyle(
                    "-fx-background-color: rgba(255,255,255,0.04);" +
                    "-fx-background-radius: 8; -fx-padding: 10 12 10 12;"
                );
                return row;
            }
        };
    }

    // ── Color Converter ──────────────────────────────────────────

    private static ToolPlugin colorConverter() {
        return new SimpleToolPlugin(
            "builtin.color", "Color Converter",
            "HEX / RGB / HSL conversion with live preview",
            "image", "1.0.0", "◉", "ic-pink"
        ) {
            @Override public Node createView() {
                TextField hexField = styledField("#5b8cf7");
                TextField rgbField = styledField("91, 140, 247");
                TextField hslField = styledField("220°, 90%, 66%");

                Region preview = new Region();
                preview.setPrefSize(80, 80);
                preview.setMinSize(80, 80);
                preview.setStyle("-fx-background-radius: 16; -fx-background-color: #5b8cf7;");

                Runnable updatePreview = () -> {
                    try {
                        String hex = hexField.getText().trim();
                        if (!hex.startsWith("#")) hex = "#" + hex;
                        preview.setStyle("-fx-background-radius: 16; -fx-background-color: " + hex + ";");
                        javafx.scene.paint.Color c = javafx.scene.paint.Color.web(hex);
                        rgbField.setText(String.format("%.0f, %.0f, %.0f",
                            c.getRed()*255, c.getGreen()*255, c.getBlue()*255));
                        hslField.setText(String.format("%.0f°, %.0f%%, %.0f%%",
                            c.getHue(), c.getSaturation()*100, c.getBrightness()*100));
                    } catch (Exception ignored) {}
                };
                hexField.textProperty().addListener((o, oldV, newV) -> updatePreview.run());

                VBox fields = new VBox(10,
                    fieldRow("HEX",  hexField),
                    fieldRow("RGB",  rgbField),
                    fieldRow("HSL",  hslField)
                );
                HBox.setHgrow(fields, Priority.ALWAYS);

                HBox top = new HBox(20, preview, fields);
                top.setAlignment(Pos.CENTER_LEFT);

                VBox root = new VBox(20, sectionLabel("Color Converter"), top);
                root.setPadding(new Insets(20));
                root.setStyle("-fx-background-color: transparent;");
                updatePreview.run();
                return root;
            }

            private HBox fieldRow(String label, TextField field) {
                Label l = new Label(label);
                l.setStyle("-fx-text-fill: rgba(255,255,255,0.40); -fx-min-width: 40px; -fx-font-size: 12px;");
                HBox.setHgrow(field, Priority.ALWAYS);
                HBox row = new HBox(12, l, field);
                row.setAlignment(Pos.CENTER_LEFT);
                return row;
            }

            private TextField styledField(String text) {
                TextField tf = new TextField(text);
                tf.setStyle(
                    "-fx-background-color: rgba(255,255,255,0.06);" +
                    "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
                    "-fx-border-radius: 8; -fx-background-radius: 8;" +
                    "-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 13px;" +
                    "-fx-padding: 8 12 8 12; -fx-font-family: 'SF Mono','Consolas',monospace;"
                );
                return tf;
            }
        };
    }

    // ── Markdown Editor ───────────────────────────────────

    private static ToolPlugin markdownEditor() {
        return new SimpleToolPlugin(
            "builtin.markdown", "Markdown",
            "实时预览 Markdown Editor",
            "text", "1.0.0", "M↓", "ic-blue"
        ) {
            @Override public Node createView() {
                TextArea editor = styledTextArea(
                    "# Hello ToolBox\n\n" +
                    "这是 **Markdown** 编辑器。\n\n" +
                    "- 支持 *斜体* 和 **粗体**\n" +
                    "- 支持列表\n" +
                    "- 支持 `代码`\n\n" +
                    "> 引用文本\n"
                );

                javafx.scene.web.WebView preview = new javafx.scene.web.WebView();
                preview.setStyle("-fx-background-color: transparent;");

                Runnable render = () -> {
                    String md = editor.getText();
                    String html = mdToHtml(md);
                    String page =
                        "<html><head><style>" +
                        "body{font-family:-apple-system,sans-serif;color:rgba(255,255,255,0.88);" +
                        "background:transparent;padding:16px;font-size:14px;line-height:1.7;}" +
                        "code{background:rgba(255,255,255,0.1);border-radius:4px;padding:2px 6px;" +
                        "font-family:monospace;}" +
                        "blockquote{border-left:3px solid #5b8cf7;margin:0;padding-left:16px;" +
                        "color:rgba(255,255,255,0.5);}" +
                        "h1,h2,h3{color:rgba(255,255,255,0.95);}" +
                        "</style></head><body>" + html + "</body></html>";
                    preview.getEngine().loadContent(page);
                };

                editor.textProperty().addListener((o, oldV, newV) -> render.run());

                VBox left  = new VBox(6, sectionLabel("编辑"), editor);
                VBox right = new VBox(6, sectionLabel("预览"), preview);
                VBox.setVgrow(editor,   Priority.ALWAYS);
                VBox.setVgrow(preview,  Priority.ALWAYS);
                HBox.setHgrow(left,  Priority.ALWAYS);
                HBox.setHgrow(right, Priority.ALWAYS);

                HBox root = new HBox(12, left, right);
                root.setPadding(new Insets(20));
                root.setStyle("-fx-background-color: transparent;");
                HBox.setHgrow(root, Priority.ALWAYS);
                VBox.setVgrow(root, Priority.ALWAYS);
                render.run();
                return root;
            }

            private String mdToHtml(String md) {
                return md
                    .replaceAll("(?m)^### (.+)$", "<h3>$1</h3>")
                    .replaceAll("(?m)^## (.+)$",  "<h2>$1</h2>")
                    .replaceAll("(?m)^# (.+)$",   "<h1>$1</h1>")
                    .replaceAll("\\*\\*(.+?)\\*\\*", "<strong>$1</strong>")
                    .replaceAll("\\*(.+?)\\*",        "<em>$1</em>")
                    .replaceAll("`(.+?)`",            "<code>$1</code>")
                    .replaceAll("(?m)^> (.+)$",       "<blockquote>$1</blockquote>")
                    .replaceAll("(?m)^- (.+)$",       "<li>$1</li>")
                    .replaceAll("(?m)^$",             "<br/>");
            }
        };
    }

    // ════════════════════════════════════════════════════
    // Shared helper methods (static factory)
    // ════════════════════════════════════════════════════

    private static TextArea styledTextArea(String prompt) {
        TextArea ta = new TextArea();
        ta.setPromptText(prompt);
