            "-fx-control-inner-background: transparent; -fx-highlight-fill: #5b8cf7;" +
            "-fx-padding: 12;"
        );
        ta.setWrapText(true);
        VBox.setVgrow(ta, Priority.ALWAYS);
        return ta;
    }

    private static Button actionButton(String text, String bg) {
        Button btn = new Button(text);
        btn.setStyle(
            "-fx-background-color: " + bg + ";" +
            "-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 13px;" +
            "-fx-background-radius: 8; -fx-border-width: 0;" +
            "-fx-padding: 8 18 8 18; -fx-cursor: hand;"
        );
        return btn;
    }

    private static Label sectionLabel(String text) {
        Label l = new Label(text.toUpperCase());
        l.setStyle(
            "-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 10px;" +
            "-fx-font-weight: bold; -fx-letter-spacing: 0.08em;"
        );
        return l;
    }

    // ════════════════════════════════════════════════════
    // Internal abstract base class: reduce built-in tool boilerplate
    // ════════════════════════════════════════════════════

    private abstract static class SimpleToolPlugin implements ToolPlugin {
        private final String id, name, desc, cat, ver, icon, iconStyle;

        SimpleToolPlugin(String id, String name, String desc,
                         String cat, String ver, String icon, String iconStyle) {
            this.id = id; this.name = name; this.desc = desc;
            this.cat = cat; this.ver = ver; this.icon = icon; this.iconStyle = iconStyle;
        }

        @Override public String getId()          { return id; }
        @Override public String getName()        { return name; }
        @Override public String getDescription() { return desc; }
        @Override public String getCategory()    { return cat; }
        @Override public String getVersion()     { return ver; }
        @Override public String getIconText()    { return icon; }
        @Override public String getIconStyle()   { return iconStyle; }

        // ToolPlugin requires getType() — built-in tools return "builtin"
        public String getType() { return "builtin"; }
    }
}
